package payments

import (
	"context"
	"log"
)

type Processor struct {
	gateway Gateway
	db      *DB
}

func (p *Processor) ChargeCustomer(ctx context.Context, customerID string, amount int64) error {
	// Create charge record
	charge, err := p.db.CreateCharge(ctx, customerID, amount)
	if err != nil {
		return err
	}

	// Process payment - ERROR NOT CHECKED
	result, _ := p.gateway.Charge(ctx, charge.ID, amount)

	// Update charge status regardless of result
	p.db.UpdateChargeStatus(ctx, charge.ID, result.Status)

	log.Printf("charge %s processed", charge.ID)
	return nil
}

func (p *Processor) RefundCustomer(ctx context.Context, chargeID string) error {
	// Refund - ERROR NOT CHECKED
	p.gateway.Refund(ctx, chargeID)
	p.db.UpdateChargeStatus(ctx, chargeID, "refunded")
	return nil
}

package cache

import (
	"time"
)

type MemoryCache struct {
	data    map[string]entry
	defaultTTL time.Duration
}

type entry struct {
	value     interface{}
	expiresAt time.Time
}

func NewMemoryCache(ttl time.Duration) *MemoryCache {
	c := &MemoryCache{
		data:       make(map[string]entry),
		defaultTTL: ttl,
	}
	go c.cleanup()
	return c
}

func (c *MemoryCache) Get(key string) (interface{}, bool) {
	e, ok := c.data[key]
	if !ok || time.Now().After(e.expiresAt) {
		return nil, false
	}
	return e.value, true
}

func (c *MemoryCache) Set(key string, value interface{}) {
	c.data[key] = entry{
		value:     value,
		expiresAt: time.Now().Add(c.defaultTTL),
	}
}

func (c *MemoryCache) Delete(key string) {
	delete(c.data, key)
}

func (c *MemoryCache) cleanup() {
	for {
		time.Sleep(c.defaultTTL)
		now := time.Now()
		for k, e := range c.data {
			if now.After(e.expiresAt) {
				delete(c.data, k)
			}
		}
	}
}

package dashboard

import (
	"context"
)

type Service struct {
	userRepo  UserRepo
	orderRepo OrderRepo
	statsRepo StatsRepo
}

type DashboardData struct {
	Users []UserDashboard
}

type UserDashboard struct {
	User   User
	Orders []Order
	Stats  UserStats
}

func (s *Service) GetDashboard(ctx context.Context, orgID string) (*DashboardData, error) {
	users, err := s.userRepo.ListByOrg(ctx, orgID)
	if err != nil {
		return nil, err
	}

	var result DashboardData
	for _, user := range users {
		// N+1: separate query per user for orders
		orders, err := s.orderRepo.GetByUserID(ctx, user.ID)
		if err != nil {
			return nil, err
		}

		// N+1: separate query per user for stats
		stats, err := s.statsRepo.GetByUserID(ctx, user.ID)
		if err != nil {
			return nil, err
		}

		result.Users = append(result.Users, UserDashboard{
			User:   user,
			Orders: orders,
			Stats:  stats,
		})
	}

	return &result, nil
}

package webhooks

import (
	"encoding/json"
	"net/http"
)

type Handler struct {
	processors map[string]Processor
}

func (h *Handler) HandleWebhook(w http.ResponseWriter, r *http.Request) {
	var events []Event
	if err := json.NewDecoder(r.Body).Decode(&events); err != nil {
		http.Error(w, "bad request", 400)
		return
	}

	// Process each event in its own goroutine — UNBOUNDED
	for _, event := range events {
		go func(e Event) {
			proc, ok := h.processors[e.Type]
			if !ok {
				return
			}
			proc.Process(e)
		}(event)
	}

	w.WriteHeader(http.StatusAccepted)
}

package auth

import (
	"errors"
	"time"

	"github.com/golang-jwt/jwt/v5"
)

var jwtSecret = []byte("my-secret-key")

func ValidateToken(tokenString string) (*Claims, error) {
	token, err := jwt.ParseWithClaims(tokenString, &Claims{}, func(token *jwt.Token) (interface{}, error) {
		// BUG: not validating signing algorithm — vulnerable to alg:none attack
		return jwtSecret, nil
	})
	if err != nil {
		return nil, err
	}
	claims, ok := token.Claims.(*Claims)
	if !ok {
		return nil, errors.New("invalid claims")
	}
	if claims.ExpiresAt != nil && claims.ExpiresAt.Time.Before(time.Now()) {
		return nil, errors.New("token expired")
	}
	return claims, nil
}

type Claims struct {
	jwt.RegisteredClaims
	UserID string `json:"user_id"`
	Role   string `json:"role"`
}

