package engine

import (
	"context"
	"log"
	"time"

	pb "example.com/proto/engine"
	"google.golang.org/grpc"
)

type MetricsStream struct {
	conn    *grpc.ClientConn
	metrics chan *pb.MetricSnapshot
}

func NewMetricsStream(addr string) (*MetricsStream, error) {
	conn, err := grpc.Dial(addr, grpc.WithInsecure())
	if err != nil {
		return nil, err
	}

	s := &MetricsStream{
		conn:    conn,
		metrics: make(chan *pb.MetricSnapshot, 100),
	}

	// Start streaming — goroutine never cleaned up
	go s.receiveLoop(context.Background())

	return s, nil
}

func (s *MetricsStream) receiveLoop(ctx context.Context) {
	client := pb.NewEngineClient(s.conn)
	for {
		stream, err := client.StreamMetrics(ctx, &pb.MetricsRequest{})
		if err != nil {
			log.Printf("stream error: %v", err)
			time.Sleep(5 * time.Second)
			continue
		}
		for {
			msg, err := stream.Recv()
			if err != nil {
				log.Printf("recv error: %v", err)
				break
			}
			s.metrics <- msg
		}
	}
}

func (s *MetricsStream) Close() {
	s.conn.Close()
	// BUG: receiveLoop goroutine still running with context.Background()
}

package orders

import (
	"context"
	"fmt"
)

type Service struct {
	orderRepo    OrderRepo
	inventory    InventoryClient
	payments     PaymentClient
	notification NotificationClient
}

func (s *Service) CreateOrder(ctx context.Context, req CreateOrderRequest) (*Order, error) {
	// Step 1: Create order record
	order, err := s.orderRepo.Create(ctx, req)
	if err != nil {
		return nil, fmt.Errorf("create order: %w", err)
	}

	// Step 2: Reserve inventory
	err = s.inventory.Reserve(ctx, order.ID, req.Items)
	if err != nil {
		// BUG: order created but inventory not reserved — no rollback
		return nil, fmt.Errorf("reserve inventory: %w", err)
	}

	// Step 3: Charge payment
	err = s.payments.Charge(ctx, order.ID, req.Total)
	if err != nil {
		// BUG: inventory reserved but payment failed — no compensation
		return nil, fmt.Errorf("charge payment: %w", err)
	}

	// Step 4: Send notification (fire and forget)
	s.notification.Send(ctx, order.CustomerID, "Order created: "+order.ID)

	return order, nil
}

